import { AsyncSeriesHook, AsyncSeriesWaterfallHook, SyncHook } from 'tapable';
import type { BeltContext, CheckResult, CommandDefinition } from './types.js';

export class BeltHooks {
  readonly initialize = new AsyncSeriesHook<[BeltContext]>(['context']);
  readonly beforeCheck = new AsyncSeriesHook<[BeltContext]>(['context']);
  readonly checkResults = new AsyncSeriesWaterfallHook<[CheckResult[], BeltContext]>([
    'results',
    'context',
  ]);
  readonly afterCheck = new AsyncSeriesHook<[CheckResult[], BeltContext]>(['results', 'context']);
  readonly registerCommands = new AsyncSeriesWaterfallHook<[CommandDefinition[], BeltContext]>([
    'commands',
    'context',
  ]);
  readonly beforeCommand = new AsyncSeriesHook<[CommandDefinition, BeltContext]>([
    'command',
    'context',
  ]);
  readonly afterCommand = new AsyncSeriesHook<[CommandDefinition, BeltContext]>([
    'command',
    'context',
  ]);
  readonly log = new SyncHook<[string, 'info' | 'warn' | 'error' | 'debug']>(['message', 'level']);
  readonly shutdown = new AsyncSeriesHook<[BeltContext]>(['context']);
}

