import path from 'node:path';
import ts from 'typescript';
import type { CheckMessage } from '@belt/core';
import type { TypecheckOptions, TypecheckResult } from './types.js';

interface RunOptions extends TypecheckOptions {
  cwd: string;
}

export async function runTypecheck(options: RunOptions): Promise<TypecheckResult> {
  const startTime = performance.now();
  const {
    cwd,
    include = ['src'],
    exclude = ['node_modules'],
    tsconfig = 'tsconfig.json',
    onlyErrors = true,
    files,
  } = options;

  const includePaths = files?.length
    ? files.map((f) => path.resolve(cwd, f))
    : include.map((dir) => path.join(cwd, dir));

  const configPath = ts.findConfigFile(cwd, ts.sys.fileExists, tsconfig);

  if (!configPath) {
    return {
      success: false,
      errorCount: 1,
      warningCount: 0,
      messages: [{ severity: 'error', message: `Could not find ${tsconfig} in ${cwd}` }],
      filesChecked: 0,
      duration: performance.now() - startTime,
    };
  }

  const configFile = ts.readConfigFile(configPath, ts.sys.readFile);
  const { options: compilerOptions, fileNames } = ts.parseJsonConfigFileContent(
    configFile.config,
    ts.sys,
    path.dirname(configPath),
    { noEmit: true },
  );

  const filesToCheck = files?.length ? includePaths : fileNames;

  const program = ts.createProgram({
    rootNames: filesToCheck,
    options: compilerOptions,
  });

  const allDiagnostics = ts.getPreEmitDiagnostics(program);
  const messages: CheckMessage[] = [];

  for (const diagnostic of allDiagnostics) {
    if (onlyErrors && diagnostic.category !== ts.DiagnosticCategory.Error) {
      continue;
    }

    const location = getDiagnosticLocation(diagnostic, cwd);

    if (location.filePath) {
      const isIncluded = includePaths.some((p) => location.filePath?.startsWith(p));
      const isExcluded = exclude.some((pattern) => location.filePath?.includes(pattern));

      if (!isIncluded || isExcluded) continue;
    }

    const message = ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n');

    messages.push({
      severity: diagnostic.category === ts.DiagnosticCategory.Error ? 'error' : 'warning',
      message,
      file: location.relativePath,
      line: location.line,
      column: location.column,
      ruleId: `TS${diagnostic.code}`,
    });
  }

  const errorCount = messages.filter((m) => m.severity === 'error').length;
  const warningCount = messages.filter((m) => m.severity === 'warning').length;

  return {
    success: errorCount === 0,
    errorCount,
    warningCount,
    messages,
    filesChecked: filesToCheck.length,
    duration: Math.round(performance.now() - startTime),
  };
}

function getDiagnosticLocation(diagnostic: ts.Diagnostic, cwd: string) {
  const { file } = diagnostic;

  if (!file || diagnostic.start === undefined) {
    return {};
  }

  const { line, character } = file.getLineAndCharacterOfPosition(diagnostic.start);

  return {
    filePath: file.fileName,
    relativePath: path.relative(cwd, file.fileName),
    line: line + 1,
    column: character + 1,
  };
}

