import path from 'node:path';
import ts from 'typescript';
import type { DiscoveredImport, GeneratedModule } from './types.js';

interface GenerateOptions {
  imports: DiscoveredImport[];
  projectPath: string;
  maxDepth: number;
  cwd: string;
}

export async function generateDeclarations(options: GenerateOptions): Promise<GeneratedModule[]> {
  const { imports, projectPath, maxDepth, cwd } = options;

  const configPath = ts.findConfigFile(projectPath, ts.sys.fileExists, 'tsconfig.json');
  if (!configPath) {
    throw new Error(`Could not find tsconfig.json in ${projectPath}`);
  }

  const configFile = ts.readConfigFile(configPath, ts.sys.readFile);
  const parsedConfig = ts.parseJsonConfigFileContent(configFile.config, ts.sys, projectPath);

  const host = ts.createCompilerHost(parsedConfig.options);
  const program = ts.createProgram(parsedConfig.fileNames, parsedConfig.options, host);
  const checker = program.getTypeChecker();

  const modules: GeneratedModule[] = [];
  const visited = new Set<string>();

  for (const imp of imports) {
    const generated = processImport(imp.specifier, projectPath, program, checker, host, visited, 0, maxDepth, cwd);
    modules.push(...generated);
  }

  return modules;
}

function processImport(
  specifier: string,
  projectPath: string,
  program: ts.Program,
  checker: ts.TypeChecker,
  host: ts.CompilerHost,
  visited: Set<string>,
  depth: number,
  maxDepth: number,
  cwd: string,
): GeneratedModule[] {
  if (depth > maxDepth) return [];

  const virtualSource = path.join(projectPath, '__virtual__.ts');
  const resolved = ts.resolveModuleName(specifier, virtualSource, program.getCompilerOptions(), host);

  const fileName = resolved.resolvedModule?.resolvedFileName;
  if (!fileName || visited.has(fileName)) return [];

  visited.add(fileName);

  const sourceFile = program.getSourceFile(fileName);
  if (!sourceFile) return [];

  const moduleSymbol = checker.getSymbolAtLocation(sourceFile);
  if (!moduleSymbol) return [];

  const exports = checker.getExportsOfModule(moduleSymbol);
  const parts: string[] = [];

  for (const exp of exports) {
    const declaration = exp.valueDeclaration ?? exp.declarations?.[0];
    if (!declaration) continue;

    if (ts.isImportSpecifier(declaration)) continue;

    if (
      ts.isInterfaceDeclaration(declaration) ||
      ts.isTypeAliasDeclaration(declaration) ||
      ts.isEnumDeclaration(declaration) ||
      ts.isClassDeclaration(declaration)
    ) {
      parts.push(declaration.getText(sourceFile));
    } else {
      const type = checker.getTypeOfSymbolAtLocation(exp, declaration);
      const typeString = checker.typeToString(type, declaration, ts.TypeFormatFlags.NoTruncation);

      if (typeString !== 'any') {
        const name = exp.getName();
        if (name === 'default') {
          parts.push(`export default {} as ${typeString};`);
        } else {
          parts.push(`export declare const ${name}: ${typeString};`);
        }
      }
    }
  }

  if (parts.length === 0) return [];

  return [
    {
      specifier,
      fileName,
      body: parts.join('\n\n'),
    },
  ];
}

