import fs from 'node:fs';
import path from 'node:path';
import type { GeneratedModule } from './types.js';

const HEADER = `/* Auto-generated by @belt/plugin-sync-types */
/* Do not edit manually */

`;

export async function writeDeclarations(modules: GeneratedModule[], outputPath: string): Promise<void> {
  const dir = path.dirname(outputPath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  let content = HEADER;

  for (const mod of modules) {
    content += `declare module '${mod.specifier}' {\n`;
    content += mod.body
      .split('\n')
      .map((line) => (line ? `  ${line}` : ''))
      .join('\n');
    content += '\n}\n\n';
  }

  fs.writeFileSync(outputPath, content, 'utf8');
}

