import * as tapable from 'tapable';
import { AsyncSeriesHook, AsyncSeriesWaterfallHook, SyncHook } from 'tapable';

interface BeltConfig {
    projectName?: string;
    rootDir?: string;
    verbose?: boolean;
    plugins?: Record<string, unknown>;
}
interface BeltContext {
    cwd: string;
    config: BeltConfig;
    hooks: BeltHooks;
    log: {
        info: (message: string) => void;
        warn: (message: string) => void;
        error: (message: string) => void;
        debug: (message: string) => void;
    };
}
interface CommandDefinition {
    id: string;
    name: string;
    description: string;
    category?: string;
    shortcut?: string;
    handler: CommandHandler;
}
type CommandHandler = (ctx: BeltContext, args?: string[]) => Promise<void> | void;
interface BeltPlugin {
    name: string;
    version?: string;
    apply: (belt: Belt) => void | Promise<void>;
}
interface CheckResult {
    success: boolean;
    errorCount: number;
    warningCount: number;
    messages: CheckMessage[];
    duration: number;
}
interface CheckMessage {
    severity: 'error' | 'warning' | 'info';
    message: string;
    file?: string;
    line?: number;
    column?: number;
    ruleId?: string;
}

declare class BeltHooks {
    readonly initialize: AsyncSeriesHook<[BeltContext], tapable.UnsetAdditionalOptions>;
    readonly beforeCheck: AsyncSeriesHook<[BeltContext], tapable.UnsetAdditionalOptions>;
    readonly checkResults: AsyncSeriesWaterfallHook<[CheckResult[], BeltContext], CheckResult[], tapable.UnsetAdditionalOptions>;
    readonly afterCheck: AsyncSeriesHook<[CheckResult[], BeltContext], tapable.UnsetAdditionalOptions>;
    readonly registerCommands: AsyncSeriesWaterfallHook<[CommandDefinition[], BeltContext], CommandDefinition[], tapable.UnsetAdditionalOptions>;
    readonly beforeCommand: AsyncSeriesHook<[CommandDefinition, BeltContext], tapable.UnsetAdditionalOptions>;
    readonly afterCommand: AsyncSeriesHook<[CommandDefinition, BeltContext], tapable.UnsetAdditionalOptions>;
    readonly log: SyncHook<[string, "error" | "info" | "warn" | "debug"], void, tapable.UnsetAdditionalOptions>;
    readonly shutdown: AsyncSeriesHook<[BeltContext], tapable.UnsetAdditionalOptions>;
}

declare class Belt {
    readonly hooks: BeltHooks;
    readonly config: BeltConfig;
    private plugins;
    private commands;
    private initialized;
    private context;
    constructor(config?: BeltConfig);
    private createContext;
    private log;
    use(plugin: BeltPlugin): this;
    registerCommand(command: CommandDefinition): this;
    getCommands(): CommandDefinition[];
    initialize(): Promise<void>;
    runCommand(commandId: string, args?: string[]): Promise<void>;
    check(): Promise<CheckResult[]>;
    shutdown(): Promise<void>;
}
declare function createBelt(config?: BeltConfig): Belt;

export { Belt, type BeltConfig, type BeltContext, BeltHooks, type BeltPlugin, type CheckMessage, type CheckResult, type CommandDefinition, type CommandHandler, createBelt };

