import { BeltPlugin } from '@belt/core';

interface SyncTypesOptions {
    /** Path to the source project (e.g., SuperApp) */
    sourceProject: string;
    /** Import patterns to discover (e.g., ['~/**']) */
    importPatterns?: string[];
    /** Patterns to ignore */
    ignorePatterns?: string[];
    /** Output file path for generated declarations */
    outputPath?: string;
    /** Max depth for recursive type extraction */
    maxDepth?: number;
}

declare function syncTypesPlugin(options: SyncTypesOptions): BeltPlugin;

export { type SyncTypesOptions, syncTypesPlugin };

